INSERT INTO b VALUES('1119364', '2.11.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '2.11.0.00.0.00.06.0000', '12792734260', 3, 'Pelaksanaan akuntabilitas kinerja Dinas Lingkungan Hidup masih perlu dilakukan penguatan koordinasi', 'Pelaksanaan akuntabilitas kinerja Dinas Lingkungan Hidup masih perlu dilakukan penguatan koordinasi', 'evaluasi kinerja rapat internal kantor', NULL, '2025');
INSERT INTO b VALUES('1119364', '2.11.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '2.11.0.00.0.00.06.0000', '12792734260', 1, 'Pendanaan yang terbatas membuat beberapa program tidak berjalan optimal.', 'Sinergi antar-kabupaten/kota dalam berbagi sumber daya dan pengalaman bisa meningkatkan efektivitas program.', 'Mengalokasikan anggaran secara strategis untuk sektor-sektor yang paling membutuhkan.', NULL, '2025');
