INSERT INTO b VALUES('1119397', '2.11.02', 'PROGRAM PERENCANAAN LINGKUNGAN HIDUP', '2.11.0.00.0.00.06.0000', '315313600', 3, 'Keterlambatan perbaikan dokumen atas verifikasi Dokumen KLHS Kabupaten/Kota', 'Adanya koordinasi dan monitoring secara berkala terkait pemenuhan target verifikasi dokumen', 'memberikan penegasan dan berkoordinasi dengan pihak yang diminta memenuhi pemverifikasian dokumen KLHS Kabupaten/Kota', NULL, '2025');
INSERT INTO b VALUES('1119397', '2.11.02', 'PROGRAM PERENCANAAN LINGKUNGAN HIDUP', '2.11.0.00.0.00.06.0000', '315313600', 1, 'Pengambilan keputusan yang kurang berbasis data dapat menyebabkan kebijakan yang tidak efektif.', 'Kerja sama antara pemerintah, akademisi, komunitas, dan sektor swasta mempercepat implementasi strategi yang lebih ramah lingkungan.', 'Mendorong studi yang lebih mendalam sebagai dasar perencanaan yang lebih akurat.', NULL, '2025');
INSERT INTO b VALUES('1119397', '2.11.02', 'PROGRAM PERENCANAAN LINGKUNGAN HIDUP', '2.11.0.00.0.00.06.0000', '315313600', 2, 'Pengambilan keputusan yang kurang berbasis data dapat menyebabkan kebijakan yang tidak efektif.', 'Kerja sama antara pemerintah, akademisi, komunitas, dan sektor swasta mempercepat implementasi strategi yang lebih ramah lingkungan.', 'Mendorong studi yang lebih mendalam sebagai dasar perencanaan yang lebih akurat.', NULL, '2025');
INSERT INTO b VALUES('1119397', '2.11.02', 'PROGRAM PERENCANAAN LINGKUNGAN HIDUP', '2.11.0.00.0.00.06.0000', '315313600', 4, 'Keterlambatan perbaikan dokumen atas verifikasi Dokumen KLHS Kabupaten/Kota', 'Adanya koordinasi dan monitoring secara berkala terkait pemenuhan target verifikasi dokumen', 'memberikan penegasan dan berkoordinasi dengan pihak yang diminta memenuhi pemverifikasian dokumen KLHS Kabupaten/Kota', NULL, '2025');
INSERT INTO b VALUES('1119400', '2.11.03', 'PROGRAM PENGENDALIAN PENCEMARAN DAN/ATAU KERUSAKAN LINGKUNGAN HIDUP', '2.11.0.00.0.00.06.0000', '1928647600', 3, 'Kondisi topografi yang ekstrim dan cuaca mempengaruhi pengambilan sampler Indikator Indeks Kualitas Lingkungan Hidup saat melakukan monev', 'Koordinasi dengan pejabat setempat untuk membantu kemudahan akses akomodasi dan transport proses pengambilan sampler Indikator Indeks Kualitas Lingkungan Hidup saat melakukan monev', 'Menjadwalkan kegiatan dengan pejabat setempat untuk membantu kemudahan akses sebagai proses pengambilan sampler Indikator Indeks Kualitas Lingkungan Hidup saat melakukan monev', NULL, '2025');
INSERT INTO b VALUES('1119400', '2.11.03', 'PROGRAM PENGENDALIAN PENCEMARAN DAN/ATAU KERUSAKAN LINGKUNGAN HIDUP', '2.11.0.00.0.00.06.0000', '1928647600', 1, 'Perubahan iklim dapat memperburuk pencemaran lingkungan dan kerusakan alam, sehingga membuat program pengendalian lebih sulit dijalankan.', 'Faktor pendorong dari Program Pengendalian Pencemaran dan/atau Kerusakan Lingkungan Hidup sangat dipengaruhi oleh kebutuhan mendesak untuk melindungi lingkungan dan kesehatan manusia, serta kewajiban untuk mematuhi regulasi dan perjanjian internasional. Faktor-faktor tersebut meliputi tantangan pencemaran yang semakin meningkat, perubahan iklim, teknologi baru, serta kesadaran masyarakat yang semakin berkembang. Selain itu, pendidikan lingkungan, keterlibatan sektor swasta, dan tuntutan pembangunan berkelanjutan juga berperan penting dalam mendorong program-program pengendalian pencemaran yang lebih efektif dan holistik.', 'Tindak lanjut dari faktor pendorong Program Pengendalian Pencemaran dan/atau Kerusakan Lingkungan Hidup melibatkan berbagai langkah yang terkoordinasi dan melibatkan banyak pemangku kepentingan. Ini termasuk penguatan kebijakan dan regulasi, pemanfaatan teknologi ramah lingkungan, peningkatan kesadaran masyarakat, serta kolaborasi dengan sektor swasta. Dengan langkah-langkah ini, program pengendalian pencemaran dapat berjalan secara lebih efektif, tidak hanya mengurangi dampak lingkungan tetapi juga menciptakan keberlanjutan sosial dan ekonomi yang berimbang', NULL, '2025');
INSERT INTO b VALUES('1119400', '2.11.03', 'PROGRAM PENGENDALIAN PENCEMARAN DAN/ATAU KERUSAKAN LINGKUNGAN HIDUP', '2.11.0.00.0.00.06.0000', '1928647600', 2, 'Perubahan iklim dapat memperburuk pencemaran lingkungan dan kerusakan alam, sehingga membuat program pengendalian lebih sulit dijalankan.', 'Faktor pendorong dari Program Pengendalian Pencemaran dan/atau Kerusakan Lingkungan Hidup sangat dipengaruhi oleh kebutuhan mendesak untuk melindungi lingkungan dan kesehatan manusia, serta kewajiban untuk mematuhi regulasi dan perjanjian internasional. Faktor-faktor tersebut meliputi tantangan pencemaran yang semakin meningkat, perubahan iklim, teknologi baru, serta kesadaran masyarakat yang semakin berkembang. Selain itu, pendidikan lingkungan, keterlibatan sektor swasta, dan tuntutan pembangunan berkelanjutan juga berperan penting dalam mendorong program-program pengendalian pencemaran yang lebih efektif dan holistik.', 'Tindak lanjut dari faktor pendorong Program Pengendalian Pencemaran dan/atau Kerusakan Lingkungan Hidup melibatkan berbagai langkah yang terkoordinasi dan melibatkan banyak pemangku kepentingan. Ini termasuk penguatan kebijakan dan regulasi, pemanfaatan teknologi ramah lingkungan, peningkatan kesadaran masyarakat, serta kolaborasi dengan sektor swasta. Dengan langkah-langkah ini, program pengendalian pencemaran dapat berjalan secara lebih efektif, tidak hanya mengurangi dampak lingkungan tetapi juga menciptakan keberlanjutan sosial dan ekonomi yang berimbang', NULL, '2025');
INSERT INTO b VALUES('1119400', '2.11.03', 'PROGRAM PENGENDALIAN PENCEMARAN DAN/ATAU KERUSAKAN LINGKUNGAN HIDUP', '2.11.0.00.0.00.06.0000', '1928647600', 4, 'Kondisi topografi yang ekstrim dan cuaca mempengaruhi pengambilan sampler Indikator Indeks Kualitas Lingkungan Hidup saat melakukan monev', 'Koordinasi dengan pejabat setempat untuk membantu kemudahan akses akomodasi dan transport proses pengambilan sampler Indikator Indeks Kualitas Lingkungan Hidup saat melakukan monev', 'Menjadwalkan kegiatan dengan pejabat setempat untuk membantu kemudahan akses sebagai proses pengambilan sampler Indikator Indeks Kualitas Lingkungan Hidup saat melakukan monev', NULL, '2025');
