INSERT INTO b VALUES('1119407', '2.11.06', 'PROGRAM PEMBINAAN DAN PENGAWASAN TERHADAP IZIN LINGKUNGAN DAN IZIN PERLINDUNGAN DAN PENGELOLAAN LINGKUNGAN HIDUP (PPLH)', '2.11.0.00.0.00.06.0000', '801918000', 3, 'Perlu adanya tindak lanjut terkait penegasan terhadap pemenuhan Ketentuan dan Kewajiban Izin Lingkungan dan/atau Izin PPLH (penilaian Dokumen Lingkungan)', 'Peningkatan kapasitas pejabat pengawas terhadap kebutuhan dan kapasitas sebagai pengawas', 'Penegasan dalam pemenuhan target pelaporan sebagai tindak lanjut', NULL, '2025');
