INSERT INTO b VALUES('1119412', '2.11.07', 'PROGRAM PENGAKUAN KEBERADAAN MASYARAKAT HUKUM ADAT (MHA), KEARIFAN LOKAL DAN HAK MHA YANG TERKAIT DENGAN PPLH', '2.11.0.00.0.00.06.0000', '0', 1, 'Banyak MHA belum diakui melalui peraturan daerah (Perda), padahal ini syarat utama untuk legitimasi hukum dan pelaksanaan program.', 'Peningkatan pengakuan bahwa pelibatan MHA dapat memperkuat konservasi dan mencegah konflik pengelolaan sumber daya alam.', 'Membangun regulasi yang jelas dan harmonis untuk pengakuan hak MHA dan perlindungan kearifan lokal.', NULL, '2025');
