INSERT INTO b VALUES('1119422', '2.11.10', 'PROGRAM PENANGANAN PENGADUAN LINGKUNGAN HIDUP', '2.11.0.00.0.00.06.0000', '52933100', 3, 'Responsivitas masyarakat terkait layanan Pengaduan Lingkungan Hidup yang masih rendah karena tingkat kesadaran masih minim', 'Kerjasama masyarakat dalam menjaga lingkungan', 'Upaya peningkatan responsivitas melalui sosialisasi dan edukasi terkait pentingnya menjaga dan sadar lingkungan', NULL, '2025');
