INSERT INTO b VALUES('1889383', '5.02.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '5.02.4.01.0.00.23.0000', '43310815625', 1, 'SDM kurang , proses Penginputan SIRUP yang belum di Input sehingga  belum di Realisasi Belanja', 'SIRUP adalah sistem yang digunakan untuk mengelola data dan formasi terkait rumah pertanian swakarya. Jika proses penginputan data ke dalam sistem ini belum dilakukan, maka informasi yang diperlukan untuk mendukung kegiatan belanja tidak tersedia. Hal ini dapat menghambat koordinasi dan pelaksanaan program belanja.', 'Memastikan bahwa proses penginputan data ke dalam SIRUP berjalan dengan lancar dan efisien. Ini bisa dilakukan dengan memberikan pelatihan kepada petugas yang bertanggung jawab atas penginputan data.', NULL, '2025');
INSERT INTO b VALUES('1889383', '5.02.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '5.02.4.01.0.00.23.0000', '43310815625', 3, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889383', '5.02.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '5.02.4.01.0.00.23.0000', '43310815625', 4, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889410', '5.02.02', 'PROGRAM PENGELOLAAN KEUANGAN DAERAH', '5.02.4.01.0.00.23.0000', '23087987865', 1, 'SDM yang belum mampuni dalam menganalisa/mengaplikasikan dalam pelaksanaan kegiatan.', 'terjadi perubahan regulasi/kebijakan dari pusat terkait pengelola keuangan.', 'Melakukan evaluasi rutin terhadap pelaksanaan program untuk mengidentifikasi hambatan dan mencari solusi untuk memperbaikinya dan meningkatkan SDM serta sosialisasi ke perangkat daerah.', NULL, '2025');
INSERT INTO b VALUES('1889410', '5.02.02', 'PROGRAM PENGELOLAAN KEUANGAN DAERAH', '5.02.4.01.0.00.23.0000', '23087987865', 3, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889410', '5.02.02', 'PROGRAM PENGELOLAAN KEUANGAN DAERAH', '5.02.4.01.0.00.23.0000', '23087987865', 4, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889452', '5.02.03', 'PROGRAM PENGELOLAAN BARANG MILIK DAERAH', '5.02.4.01.0.00.23.0000', '37626881497', 1, 'SDM Kurang.Kode RUP Masih Menunggu.Katalog Versi 6 sehingga belum bisa pengadaan Barang Milik Daerah.Karna perubahan pajak.', 'perubahan pajak bisa menjadi penghambat karena dapat mempengaruhi biaya dan kebijakan pengadaan barang. Jika perubahan pajak tidak disesuaikan dengan sistem katalog versi 6, maka proses pengadaan bisa terhambat.', 'Memastikan bahwa kebijakan pajak disesuaikan dengan sistem katalog versi 6 sehingga tidak menghambat proses pengadaan barang. Ini termasuk pelaksanaan anggaran, pengawasan, dan evaluasi program.', NULL, '2025');
INSERT INTO b VALUES('1889452', '5.02.03', 'PROGRAM PENGELOLAAN BARANG MILIK DAERAH', '5.02.4.01.0.00.23.0000', '37626881497', 3, NULL, NULL, NULL, NULL, '2025');
