INSERT INTO b VALUES('1889467', '5.01.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '5.01.5.02.5.05.21.0000', '19007671173', 1, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889467', '5.01.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '5.01.5.02.5.05.21.0000', '19007671173', 3, '- keterlambatan laporan yang di terima dengan jadwal yang ditetapkan sehingga proses pengolahan dan penyusunan laporan menjadi tertunda\r\n- Adanya perubahan arahan dan prioritas pimpinan secara tiba-tiba menyebabkan penyesuaian kembali terhadap rencana kegiatan dan jadwal pelaksanaan, sehingga berdampak pada keterlambatan pelaksanaan program dan penyusunan laporan', '- Adanya arahan dan perhatian pimpinan terhadap pentingnya ketepatan waktu penyampaian laporan mendorong perangkat daerah untuk lebih disiplin dalam memenuhi jadwal yang ditetapkan.\r\n- arahan dan prioritas pimpinan menyesuaikan program dengan kondisi aktual sehingga kegiatan dan program yang dilaksanakan tetap relevan', '- Melakukan penyesuaian kembali rencana kegiatan dan jadwal pelaksanaan secara terencana dan terkoordinasi dengan unit kerja\r\n- membuat arahan secara tertulis kepada unit kerja penyampaian laporan  tepat waktu dan di lakukan evaluasi  kepada unit kerja yang terlambat.', NULL, '2025');
INSERT INTO b VALUES('1889467', '5.01.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '5.01.5.02.5.05.21.0000', '19007671173', 4, '- keterlambatan laporan yang di terima dengan jadwal yang ditetapkan sehingga proses pengolahan dan penyusunan laporan menjadi tertunda\r\n- Adanya perubahan arahan dan prioritas pimpinan secara tiba-tiba menyebabkan penyesuaian kembali terhadap rencana kegiatan dan jadwal pelaksanaan, sehingga berdampak pada keterlambatan pelaksanaan program dan penyusunan laporan', '- Adanya arahan dan perhatian pimpinan terhadap pentingnya ketepatan waktu penyampaian laporan mendorong perangkat daerah untuk lebih disiplin dalam memenuhi jadwal yang ditetapkan.\r\n- arahan dan prioritas pimpinan menyesuaikan program dengan kondisi aktual sehingga kegiatan dan program yang dilaksanakan tetap relevan', '- Melakukan penyesuaian kembali rencana kegiatan dan jadwal pelaksanaan secara terencana dan terkoordinasi dengan unit kerja\r\n- membuat arahan secara tertulis kepada unit kerja penyampaian laporan  tepat waktu dan di lakukan evaluasi  kepada unit kerja yang terlambat.', NULL, '2025');
INSERT INTO b VALUES('1889498', '5.01.02', 'PROGRAM PERENCANAAN, PENGENDALIAN DAN EVALUASI PEMBANGUNAN DAERAH', '5.01.5.02.5.05.21.0000', '12318779039', 1, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889498', '5.01.02', 'PROGRAM PERENCANAAN, PENGENDALIAN DAN EVALUASI PEMBANGUNAN DAERAH', '5.01.5.02.5.05.21.0000', '12318779039', 3, '-keterbatasan data dan informasi dan tidak up to date\r\n- Kapasitas SDM teknis di bidang perencanaan, monitoring, dan evaluasi belum optimal,ehingga pelaksanaan kegiatan masih memerlukan pendampingan dari akademisi atau pihak luar\r\n-RPJMD, Renstra OPD, RKPD, dan Renja OPD belum sepenuhnya selaras.', '-Telah tersedianya sistem pengelolaan data dan informasi perencanaan sebagai dasar penguatan basis data pembangunan daerah.\r\n-Tersedianya pendampingan teknis dari akademisi dan tenaga ahli sebagai upaya peningkatan kapasitas SDM perencana\r\n- Adanya kerangka dokumen perencanaan daerah yang menjadi acuan dalam proses sinkronisasi program dan kegiatan antar OPD.', '- Optimalisasi sistem pengelolaan data (SIPD, SIMEVLAP, e-SAKIP, e-Kertas Kerja, dan SampQ) dilakukan untuk memastikan ketersediaan data yang mutakhir dalam mendukung perencanaan, monitoring, dan evaluasi pembangunan daerah.\r\n- Kegiatan bimbingan teknis SDM perencana dilaksanakan setiap tahun sebagai upaya peningkatan kapasitas aparatur perencana melibatkan BAPPENAS\r\n- Mengarahkan dan memfasilitasi perangkat daerah dalam penyusunan Renstra, RKPD, dan RPJMD agar selaras dengan peraturan dan pedoman yang ditetapkan oleh Kementerian Dalam Negeri.', NULL, '2025');
INSERT INTO b VALUES('1889498', '5.01.02', 'PROGRAM PERENCANAAN, PENGENDALIAN DAN EVALUASI PEMBANGUNAN DAERAH', '5.01.5.02.5.05.21.0000', '12318779039', 4, '-keterbatasan data dan informasi dan tidak up to date\r\n- Kapasitas SDM teknis di bidang perencanaan, monitoring, dan evaluasi belum optimal,ehingga pelaksanaan kegiatan masih memerlukan pendampingan dari akademisi atau pihak luar\r\n-RPJMD, Renstra OPD, RKPD, dan Renja OPD belum sepenuhnya selaras.', '-Telah tersedianya sistem pengelolaan data dan informasi perencanaan sebagai dasar penguatan basis data pembangunan daerah.\r\n-Tersedianya pendampingan teknis dari akademisi dan tenaga ahli sebagai upaya peningkatan kapasitas SDM perencana\r\n- Adanya kerangka dokumen perencanaan daerah yang menjadi acuan dalam proses sinkronisasi program dan kegiatan antar OPD.', '- Optimalisasi sistem pengelolaan data (SIPD, SIMEVLAP, e-SAKIP, e-Kertas Kerja, dan SampQ) dilakukan untuk memastikan ketersediaan data yang mutakhir dalam mendukung perencanaan, monitoring, dan evaluasi pembangunan daerah.\r\n- Kegiatan bimbingan teknis SDM perencana dilaksanakan setiap tahun sebagai upaya peningkatan kapasitas aparatur perencana melibatkan BAPPENAS\r\n- Mengarahkan dan memfasilitasi perangkat daerah dalam penyusunan Renstra, RKPD, dan RPJMD agar selaras dengan peraturan dan pedoman yang ditetapkan oleh Kementerian Dalam Negeri.', NULL, '2025');
INSERT INTO b VALUES('1889514', '5.01.03', 'PROGRAM KOORDINASI DAN SINKRONISASI PERENCANAAN PEMBANGUNAN DAERAH', '5.01.5.02.5.05.21.0000', '5050251200', 1, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889514', '5.01.03', 'PROGRAM KOORDINASI DAN SINKRONISASI PERENCANAAN PEMBANGUNAN DAERAH', '5.01.5.02.5.05.21.0000', '5050251200', 3, '- ego sektoral sektoral masih tinggi sehingga sulit menyelaraskan prioritas pembangunan.\r\n- Koordinasi dan sinkronisasi program dan kegiatan antar OPD telah berjalan, namun efektivitasnya dalam mendukung pencapaian sasaran pembangunan daerah masih perlu ditingkatkan.', '- Kebijakan pimpinan menjadi faktor penting dalam memastikan kesesuaian program dan kegiatan dengan prioritas pembangunan daerah.\r\n- Adanya forum dan prosedur koordinasi antar OPD yang mendukung proses sinkronisasi perencanaan pembangunan daerah.', '- prioritas pembangunan daerah perlu diperkuat melalui penyusunan dan penetapan peraturan yang bersifat mengikat Peraturan tersebut dapat dituangkan dalam bentuk Peraturan Kepala Daerah, Peraturan Sekretaris Daerah, atau regulasi internal lainnya yang mengatur kewajiban perangkat daerah untuk menyelaraskan program dan kegiatan dengan dokumen perencanaan daerah (RPJMD, RKPD, dan Renstra OPD). Selain itu, penguatan kebijakan ini perlu didukung dengan penyusunan Standar Operasional Prosedur (SOP) dan Prosedur Bisnis (Probis) sebagai pedoman teknis pelaksanaan\r\n- Asistensi dan desk perencanaan dilaksanakan untuk menyelaraskan program dan kegiatan dengan sasaran pembangunan daerah.', NULL, '2025');
INSERT INTO b VALUES('1889514', '5.01.03', 'PROGRAM KOORDINASI DAN SINKRONISASI PERENCANAAN PEMBANGUNAN DAERAH', '5.01.5.02.5.05.21.0000', '5050251200', 4, '- ego sektoral sektoral masih tinggi sehingga sulit menyelaraskan prioritas pembangunan.\r\n- Koordinasi dan sinkronisasi program dan kegiatan antar OPD telah berjalan, namun efektivitasnya dalam mendukung pencapaian sasaran pembangunan daerah masih perlu ditingkatkan.', '- Kebijakan pimpinan menjadi faktor penting dalam memastikan kesesuaian program dan kegiatan dengan prioritas pembangunan daerah.\r\n- Adanya forum dan prosedur koordinasi antar OPD yang mendukung proses sinkronisasi perencanaan pembangunan daerah.', '- prioritas pembangunan daerah perlu diperkuat melalui penyusunan dan penetapan peraturan yang bersifat mengikat Peraturan tersebut dapat dituangkan dalam bentuk Peraturan Kepala Daerah, Peraturan Sekretaris Daerah, atau regulasi internal lainnya yang mengatur kewajiban perangkat daerah untuk menyelaraskan program dan kegiatan dengan dokumen perencanaan daerah (RPJMD, RKPD, dan Renstra OPD). Selain itu, penguatan kebijakan ini perlu didukung dengan penyusunan Standar Operasional Prosedur (SOP) dan Prosedur Bisnis (Probis) sebagai pedoman teknis pelaksanaan\r\n- Asistensi dan desk perencanaan dilaksanakan untuk menyelaraskan program dan kegiatan dengan sasaran pembangunan daerah.', NULL, '2025');
INSERT INTO b VALUES('1889533', '5.05.02', 'PROGRAM PENELITIAN DAN PENGEMBANGAN DAERAH', '5.01.5.02.5.05.21.0000', '14288994298', 1, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889533', '5.05.02', 'PROGRAM PENELITIAN DAN PENGEMBANGAN DAERAH', '5.01.5.02.5.05.21.0000', '14288994298', 3, '- keterbatasan data sektoral yang terintegrasi antar perangkat daerah sehingga penelitian yang telah diimplementasikan belum sepenuhnya didukung oleh basis data menyebabkan perumusan tidak sinkron dengan kondisi aktual. \r\n-fokus penelitian yang di lakukan, belum sepenuhnya yang berdampak pada pelaksanaan pembangunan daerah\r\n- kurangnya SDM kompeten/peneliti,sarana prasarana minim, serta rendahnya dukungan pemerintah daerah.', '- membangun sistem data sektoral yang terintegrasi antar perangkat daerah dalam mengimplementasikan penelitian\r\n- analisis secara komprehensif terhadap kondisi daerah, isu strategis, dan permasalahan yang berkembang di Kabupaten Mahakam Ulu sebagai dasar  fokus penelitian, sehingga hasil penelitian yang dilaksanakan dapat bersifat tepat sasaran dan memberikan kontribusi nyata terhadap pembangunan sektoral daerah\r\n- Melaksanakan kerja sama dengan perguruan tinggi dan/atau lembaga penelitian sebagai mitra akademisi dalam pelaksanaan kegiatan penelitian dan pengembangan daerah, guna memastikan metodologi penelitian yang digunakan sesuai.', '- membangun sistem aplikasi SIMPELSIBANG memudahkan dalam proses pemanfaatan data agar muthakir dan up to date\r\n- dilakukan kegiatan sosialisasi kepada perangkat daerah dan pemangku kepentingan terkait.', NULL, '2025');
INSERT INTO b VALUES('1889533', '5.05.02', 'PROGRAM PENELITIAN DAN PENGEMBANGAN DAERAH', '5.01.5.02.5.05.21.0000', '14288994298', 4, '- keterbatasan data sektoral yang terintegrasi antar perangkat daerah sehingga penelitian yang telah diimplementasikan belum sepenuhnya didukung oleh basis data menyebabkan perumusan tidak sinkron dengan kondisi aktual. \r\n-fokus penelitian yang di lakukan, belum sepenuhnya yang berdampak pada pelaksanaan pembangunan daerah\r\n- kurangnya SDM kompeten/peneliti,sarana prasarana minim, serta rendahnya dukungan pemerintah daerah.', '- membangun sistem data sektoral yang terintegrasi antar perangkat daerah dalam mengimplementasikan penelitian\r\n- analisis secara komprehensif terhadap kondisi daerah, isu strategis, dan permasalahan yang berkembang di Kabupaten Mahakam Ulu sebagai dasar  fokus penelitian, sehingga hasil penelitian yang dilaksanakan dapat bersifat tepat sasaran dan memberikan kontribusi nyata terhadap pembangunan sektoral daerah\r\n- Melaksanakan kerja sama dengan perguruan tinggi dan/atau lembaga penelitian sebagai mitra akademisi dalam pelaksanaan kegiatan penelitian dan pengembangan daerah, guna memastikan metodologi penelitian yang digunakan sesuai.', '- membangun sistem aplikasi SIMPELSIBANG memudahkan dalam proses pemanfaatan data agar muthakir dan up to date\r\n- dilakukan kegiatan sosialisasi kepada perangkat daerah dan pemangku kepentingan terkait.', NULL, '2025');
