INSERT INTO b VALUES('1889610', '7.01.02', 'PROGRAM PENYELENGGARAAN PEMERINTAHAN DAN PELAYANAN PUBLIK', '7.01.0.00.0.00.19.0000', '48050000', 1, 'partisipasi masyarakat yang minim', 'Alokasi Anggaran yang memadai', 'Mengatasi berbagai faktor penghambat ini memerlukan komitmen kuat dari pimpinan kecamatan, dukungan dari pemerintah kabupaten/kota, serta partisipasi aktif dari seluruh elemen masyarakat. Peningkatan kapasitas SDM, modernisasi sarana prasarana, penyederhanaan birokrasi, dan penguatan koordinasi menjadi kunci untuk mewujudkan pelayanan publik yang prima di tingkat kecamatan.', NULL, '2025');
