INSERT INTO b VALUES('1889613', '7.01.03', 'PROGRAM PEMBERDAYAAN MASYARAKAT DESA DAN KELURAHAN', '7.01.0.00.0.00.19.0000', '64813000', 1, 'Lembaga masyarakat (misalnya, KPMD, BPK, LPM) mungkin belum memiliki kapasitas yang memadai dalam perencanaan, pelaksanaan, pengelolaan keuangan, dan pelaporan program.', 'Alokasi Anggaran yang memadai', 'Mengatasi hambatan-hambatan ini memerlukan pendekatan holistik, mulai dari peningkatan kapasitas SDM aparatur dan masyarakat, perbaikan sistem koordinasi, penyesuaian kebijakan yang lebih fleksibel, hingga penguatan partisipasi dan mekanisme pengawasan. Dengan demikian, program pemberdayaan masyarakat di desa dan kelurahan dapat berjalan lebih efektif dan memberikan dampak positif yang berkelanjutan.', NULL, '2025');
INSERT INTO b VALUES('1889613', '7.01.03', 'PROGRAM PEMBERDAYAAN MASYARAKAT DESA DAN KELURAHAN', '7.01.0.00.0.00.19.0000', '64813000', 3, 'Lembaga masyarakat (misalnya, KPMD, BPK, LPM) mungkin belum memiliki kapasitas yang memadai dalam perencanaan, pelaksanaan, pengelolaan keuangan, dan pelaporan program.', 'Alokasi Anggaran yang memadai', 'Mengatasi hambatan-hambatan ini memerlukan pendekatan holistik, mulai dari peningkatan kapasitas SDM aparatur dan masyarakat, perbaikan sistem koordinasi, penyesuaian kebijakan yang lebih fleksibel, hingga penguatan partisipasi dan mekanisme pengawasan. Dengan demikian, program pemberdayaan masyarakat di desa dan kelurahan dapat berjalan lebih efektif dan memberikan dampak positif yang berkelanjutan.', NULL, '2025');
