INSERT INTO b VALUES('1889616', '7.01.05', 'PROGRAM PENYELENGGARAAN URUSAN PEMERINTAHAN UMUM', '7.01.0.00.0.00.19.0000', '25500000', 1, 'Staf kecamatan seringkali merangkap banyak tugas, sehingga fokus pada program ini menjadi terbagi dan tidak maksimal.', 'Alokasi Anggaran yang memadai', 'Mengatasi berbagai hambatan ini memerlukan komitmen kuat dari pemerintah daerah, peningkatan kapasitas aparatur, penyederhanaan birokrasi, serta upaya kolaboratif dengan seluruh elemen masyarakat dan instansi terkait. Dengan demikian, penyelenggaraan urusan pemerintahan umum di kecamatan dapat berjalan optimal demi terwujudnya stabilitas dan pelayanan yang prima bagi masyarakat.', NULL, '2025');
