INSERT INTO b VALUES('1889619', '7.01.06', 'PROGRAM PEMBINAAN DAN PENGAWASAN PEMERINTAHAN DESA', '7.01.0.00.0.00.19.0000', '332420000', 1, 'Kondisi geografis desa yang sulit dijangkau, keterbatasan kendaraan operasional, atau infrastruktur jalan yang buruk dapat menghambat intensitas kunjungan pembinaan dan pengawasan.', 'Alokasi Anggaran yang memadai', 'Mengatasi faktor-faktor penghambat ini memerlukan upaya komprehensif, mulai dari peningkatan kapasitas SDM kecamatan, penguatan koordinasi lintas sektor dan tingkat pemerintahan, penyempurnaan regulasi, hingga pengembangan mekanisme pembinaan dan pengawasan yang lebih partisipatif dan berbasis teknologi.', NULL, '2025');
