INSERT INTO b VALUES('1889924', '4.01.03', 'PROGRAM PEREKONOMIAN DAN PEMBANGUNAN', '4.01.0.00.0.00.14.0010', '3760077200', 3, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889924', '4.01.03', 'PROGRAM PEREKONOMIAN DAN PEMBANGUNAN', '4.01.0.00.0.00.14.0010', '3760077200', 1, 'aplikasi Sampeq belum di gunakan karena masih dalam proses dengan pihak pengembang, dan dalam pengencekan kegiatan pembangunan yang ada di kabupaten Mahakam Ulu belum terlaksana dengan optimal karena menunggu anggaran', NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889924', '4.01.03', 'PROGRAM PEREKONOMIAN DAN PEMBANGUNAN', '4.01.0.00.0.00.14.0010', '3760077200', 2, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889924', '4.01.03', 'PROGRAM PEREKONOMIAN DAN PEMBANGUNAN', '4.01.0.00.0.00.14.0010', '3760077200', 4, 'Keterbatasan SDM yang terampil dan berkualitas dapat menghambat pelaksanaan program secara efektif dan efisien.', 'Ketersediaan dana yang memadai untuk mendukung kegiatan administrasi', 'melakukan  koordinasi rutin antar-OPD dalam melakukan pengendalian terhadap pelaksanaan kegiatan', NULL, '2025');
INSERT INTO b VALUES('1889931', '4.01.03', 'PROGRAM PEREKONOMIAN DAN PEMBANGUNAN', '4.01.2.16.0.00.14.0006', '7948226800', 1, 'Mengingat banyaknya bidang urusan yang melekat pada Bagian Perekonomian dan SDA tidak sesuai dengan SDM yang ada, terutama personil ASN. Sehingga menghambat proses pelaksanaan kegiatan.', 'Untuk mendukung keberhasilan pelaksanaan kegiatan pada Bagian Perekonomian dan SDA maka perlu adanya penambahan SDM baik secara kualitas maupun kuantitas.', 'Penambahan dan pengembangan SDM.', NULL, '2025');
INSERT INTO b VALUES('1889931', '4.01.03', 'PROGRAM PEREKONOMIAN DAN PEMBANGUNAN', '4.01.2.16.0.00.14.0006', '7948226800', 3, 'Mengingat banyaknya bidang urusan yang melekat pada Bagian Perekonomian dan SDA tidak sesuai dengan SDM yang ada, terutama personil ASN. Sehingga menghambat proses pelaksanaan kegiatan.', 'Untuk mendukung keberhasilan pelaksanaan kegiatan pada Bagian Perekonomian dan SDA maka perlu adanya penambahan SDM baik secara kualitas maupun kuantitas.', 'Penambahan dan pengembangan SDM.', NULL, '2025');
INSERT INTO b VALUES('1889931', '4.01.03', 'PROGRAM PEREKONOMIAN DAN PEMBANGUNAN', '4.01.2.16.0.00.14.0006', '7948226800', 2, 'Mengingat banyaknya bidang urusan yang melekat pada Bagian Perekonomian dan SDA tidak sesuai dengan SDM yang ada, terutama personil ASN. Sehingga menghambat proses pelaksanaan kegiatan.', 'Untuk mendukung keberhasilan pelaksanaan kegiatan pada Bagian Perekonomian dan SDA maka perlu adanya penambahan SDM baik secara kualitas maupun kuantitas.', 'Penambahan dan pengembangan SDM.', NULL, '2025');
INSERT INTO b VALUES('1889931', '4.01.03', 'PROGRAM PEREKONOMIAN DAN PEMBANGUNAN', '4.01.2.16.0.00.14.0006', '7948226800', 4, 'Mengingat masih luasnya cakupan urusan pada Bidang Perekonomian dan SDA yang belum sepenuhnya didukung oleh ketersediaan SDM yang memadai khususnya Aparatur Sipil Negara, sehingga pelaksanaan kegiatan belum dapat berjalan secara optimal.', 'Dalam rangka mendukung arah keberhasilan pelaksanaan kegiatan kegiatan pada Bidang Perekonomian dan SDA kearah yang lebih optimal maka lebih diperlukan penambahan Sumber Daya Manusia yang lebih aktif dan berkompeten.', 'Peningkatan kemampuan dan profesionalisme aparatur', NULL, '2025');
INSERT INTO b VALUES('1889944', '4.01.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '4.01.2.16.0.00.14.0007', '3131371300', 1, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889944', '4.01.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '4.01.2.16.0.00.14.0007', '3131371300', 4, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('1889951', '4.01.02', 'PROGRAM PEMERINTAHAN DAN KESEJAHTERAAN RAKYAT', '4.01.2.16.2.10.14.0001', '8163384900', 3, 'Berikut rekapan faktor penghambat pada Bagian  Pemerintahan Sesuai Sub Kegiatan Pada Program Pemerintahan dan Kesejahteraan Rakyat :\r\n1. Penataan Administrasi Pemerintahan\r\n -Infrastruktur teknis yakni jaringan Internet tidak stabil\r\n-Template tata naskah dinas yang belum seragam\r\n-Sering tidak ada Berita acara dan Fakta Integritas pemegang Aset \r\n-Identifikasi faktor-faktor resiko tidak akurat \r\n2. Fasilitasi Pelaksanaan Otonomi Daerah\r\n-Kurangnya kesadaran dari masing-masing OPD Pengumpul data untuk menyampaikan data tepat waktu dan valid\r\n-Laporan realisasi kinerja masing-masing OPD Tahun 2025 sebagai sumber informasi (Bahan) utama isian LKPJ belum terkumpul secara menyeluruh \r\n-Pengisian form 4 tahapan SPM kurang maksimal\r\n3. Pengelolaan Administrasi Kewilayahan\r\n-Belum lengkapnya inventarisasi data administrasi pertanahan \r\n-Data belum seragam dan pemahaman standar penamaan masih terbatas serta sarana pendukung dan keterbatasan SDM\r\n-Akses geografis yang luas dan medan yang sulit dijangkau\r\n-Koordinasi belum optimal karena jarak dan waktu\r\n4. Fasilitasi Kerja Sama Daerah\r\n-OPD yang melaksanakan PKS belum melaporkan hasil dan tindak lanjut kerja sama yang dilaksanakan', '- Ketersediaan Anggaran\r\n- Kerja sama dan koordinasi tim\r\n- Komitmen pimpinan dan dukungan kebijakan', 'Berikut rekapan tindak lanjut terhadap faktor penghambat pada Bagian  Pemerintahan Sesuai Sub Kegiatan Pada Program Pemerintahan dan Kesejahteraan Rakyat :\r\n1. Penataan Administrasi Pemerintahan\r\n- Pengarsipan  manual (scanning dokumen) dan harus ada box file terintegrasi sesuai klasifikasi (arsip aktif/in aktif di Bagian Pemerintahan sebelum sinkronisasi jika jaringan internet sudah stabil\r\n- Pendampingan tata naskah dinas yang disesuaikan dengan Perbup dan peningkatan template naskah dinas digital\r\n- Mewajibkan pendataan penerima sebelum penyerahan aset serta  rekon aset tiap triwulan\r\n- Rapat intenal secara berkala dan pemanfataan E-SPIP terintegrasi serta pendampingan berkesinambungan oleh Auditor Internal\r\n2. Fasilitasi Pelaksanaan Otonomi Daerah\r\n- Masing-masing OPD menyampaikan paparan hasil kinerja Tahun 2025 kepada KDH sesuai jadwal\r\n- Melaksanakan Rakor percepatan penyampaian data laporan\r\n- Pengisian Form 4 tahapan SPM 2026 sebagai agenda utama pada Triwulan I 2026\r\n3. Pengelolaan Administrasi Kewilayahan\r\n- Penguatan koordinasi lintas perangkat daerah untuk melengkapi inventarisasi data\r\n- Sosialisasi standar penamaan rupabumi dan pendampingan teknis\r\n- Penjadwalan monev yang lebih efektif dan pemanfaatan laporan digital.\r\n- Optimalisasi Forum rutin agar program di Kecamatan sesuai dengan Visi-Misi Kepala Daerah\r\n4. Fasilitasi Kerja Sama Daerah\r\n- OPD yang melaksanakan Kerja Sama Tahun 2026 menyampaikan laporan hasil kegiatan\r\n- Menunggu konfirmasi OPD yang akan melaksanakan PKS 2026', NULL, '2025');
INSERT INTO b VALUES('1889951', '4.01.02', 'PROGRAM PEMERINTAHAN DAN KESEJAHTERAAN RAKYAT', '4.01.2.16.2.10.14.0001', '8163384900', 1, 'Faktor penghambat keberhasilan kinerja Bagian Pemerintahan Sekretariat Daerah Kabupaten Mahakam Ulu Secara Umum Dapat Diuraikan Sebagai berikut : \r\na). Terkhusus terkait batas daerah, terdapat faktor Kepentingan Antar Daerah/Warga Sekitar Perbatasan. b). Sulitnya Jangkauan Objek Pendataan. c).Konflik Antar Warga Masyarakat Pemilik Hak Tanah. d).Minimnya pengetahuan penyelenggaran kegiatan/event berskala besar e).Masih minimnya jumlah SDM Aparatur yang berkompeten/konsen dibidangnya f).Terkait Pelaporan terkendala pada keterlambatan data yang disampaikan oleh OPD', 'a).Sumber Daya Manusia/ Aparatur Bagian Pemerintahan yang bertanggungjawab terhadap tugas Pokok dan Fungsinya b).Ketersediaan anggaran untuk mendukung pelaksanaan Kegiatan', 'Tindak lanjut yang dilakukan oleh Bagian Pemerintahan diuraikan sebagai berikut :a). Melakukan mediasi antar masyarakat yang berkonflik b). Pembedayaan dengan melakukan peningkatan kualitas kinerja aparatur\r\nc). Koordinasi dan kosultasi antar OPD pemangku data pelaporan dengan mengadirkan narasumber ahli maupun praktisi', NULL, '2025');
INSERT INTO b VALUES('1889951', '4.01.02', 'PROGRAM PEMERINTAHAN DAN KESEJAHTERAAN RAKYAT', '4.01.2.16.2.10.14.0001', '8163384900', 4, 'Berikut rekapan faktor penghambat pada Bagian  Pemerintahan Sesuai Sub Kegiatan Pada Program Pemerintahan dan Kesejahteraan Rakyat :\r\n1. Penataan Administrasi Pemerintahan\r\n -Infrastruktur teknis yakni jaringan Internet tidak stabil\r\n-Template tata naskah dinas yang belum seragam\r\n-Sering tidak ada Berita acara dan Fakta Integritas pemegang Aset \r\n-Identifikasi faktor-faktor resiko tidak akurat \r\n2. Fasilitasi Pelaksanaan Otonomi Daerah\r\n-Kurangnya kesadaran dari masing-masing OPD Pengumpul data untuk menyampaikan data tepat waktu dan valid\r\n-Laporan realisasi kinerja masing-masing OPD Tahun 2025 sebagai sumber informasi (Bahan) utama isian LKPJ belum terkumpul secara menyeluruh \r\n-Pengisian form 4 tahapan SPM kurang maksimal\r\n3. Pengelolaan Administrasi Kewilayahan\r\n-Belum lengkapnya inventarisasi data administrasi pertanahan \r\n-Data belum seragam dan pemahaman standar penamaan masih terbatas serta sarana pendukung dan keterbatasan SDM\r\n-Akses geografis yang luas dan medan yang sulit dijangkau\r\n-Koordinasi belum optimal karena jarak dan waktu\r\n4. Fasilitasi Kerja Sama Daerah\r\n-OPD yang melaksanakan PKS belum melaporkan hasil dan tindak lanjut kerja sama yang dilaksanakan', '- Ketersediaan Anggaran\r\n- Kerja sama dan koordinasi tim\r\n- Komitmen pimpinan dan dukungan kebijakan', 'Berikut rekapan tindak lanjut terhadap faktor penghambat pada Bagian  Pemerintahan Sesuai Sub Kegiatan Pada Program Pemerintahan dan Kesejahteraan Rakyat :\r\n1. Penataan Administrasi Pemerintahan\r\n- Pengarsipan  manual (scanning dokumen) dan harus ada box file terintegrasi sesuai klasifikasi (arsip aktif/in aktif di Bagian Pemerintahan sebelum sinkronisasi jika jaringan internet sudah stabil\r\n- Pendampingan tata naskah dinas yang disesuaikan dengan Perbup dan peningkatan template naskah dinas digital\r\n- Mewajibkan pendataan penerima sebelum penyerahan aset serta  rekon aset tiap triwulan\r\n- Rapat intenal secara berkala dan pemanfataan E-SPIP terintegrasi serta pendampingan berkesinambungan oleh Auditor Internal\r\n2. Fasilitasi Pelaksanaan Otonomi Daerah\r\n- Masing-masing OPD menyampaikan paparan hasil kinerja Tahun 2025 kepada KDH sesuai jadwal\r\n- Melaksanakan Rakor percepatan penyampaian data laporan\r\n- Pengisian Form 4 tahapan SPM 2026 sebagai agenda utama pada Triwulan I 2026\r\n3. Pengelolaan Administrasi Kewilayahan\r\n- Penguatan koordinasi lintas perangkat daerah untuk melengkapi inventarisasi data\r\n- Sosialisasi standar penamaan rupabumi dan pendampingan teknis\r\n- Penjadwalan monev yang lebih efektif dan pemanfaatan laporan digital.\r\n- Optimalisasi Forum rutin agar program di Kecamatan sesuai dengan Visi-Misi Kepala Daerah\r\n4. Fasilitasi Kerja Sama Daerah\r\n- OPD yang melaksanakan Kerja Sama Tahun 2026 menyampaikan laporan hasil kegiatan\r\n- Menunggu konfirmasi OPD yang akan melaksanakan PKS 2026', NULL, '2025');
