INSERT INTO b VALUES('1890009', '4.02.02', 'PROGRAM DUKUNGAN PELAKSANAAN TUGAS DAN FUNGSI DPRD', '4.02.0.00.0.00.15.0000', '26757995700', 1, 'Masih lemahnya pemahaman Anggota DPRD terhadap pelaksanaan tugas dan fungsinya dan  Tumpang tindihnya\r\nkepentingan antar fraksi', 'Terfasilitasinya sarana dan prasarana kebutuhan DPRD', 'Perlu melakukan koordinasi untuk meningkatkan kualitas DPRD', NULL, '2025');
