INSERT INTO b VALUES('22289264', '8.01.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '8.01.0.00.0.00.25.0000', '10441505573', 1, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('22289264', '8.01.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '8.01.0.00.0.00.25.0000', '10441505573', 3, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('22289264', '8.01.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '8.01.0.00.0.00.25.0000', '10441505573', 4, 'terdapat dalam Realisasi Penyerapan Anggaran tidak terlaksana 100 % pada sehingga terdapat sisa Pengunaan Anggaran Pada APBP Rp.2.196.008756 terjadi Karena hal- hal sebagai berikut\r\n1.  Kegiatan administrasi  Keuangan Perangkat Daerah Penyediaan Gaji dan Tunjang ASN, Pada saat Penganggran jumlah Pegawai ASN yang di Anggarkan berjumlah 25 orang, pada Praktek nya yang menduduki Jabatan Ada 22 dikarenakan belum ada pejabat Devinitif dan adanya Mutasi Jabatan Sekretaris Ke Opd yang lain, sehingga dana tidak dapat siserap  100% . \r\n2. gaji Pegawai Non Asn yang dianggarkan terjadi perubahan Jumlah karena 11 orang lulus seleksi PPPK, Sehingga pada Rekening pada Jasa Pelayanan Umum Kantor terjadi perubahan penyerapan Anggarannya. \r\n3. terdapat 3 Pegawai  yang namanya tidak terdaftar pada Pengumuman Data Pegawai PPPK Paru waktu. sehingga menghambat Pemberian Gaji.', 'dan perubahan jumlah Pagu khusus untuk PPPK dan PPPK Paru waktu pada APBDP. Sehingga memudahkan untuk penggunaan Anggaran untuk membayar Gaji dan Tunjangan ASN dan NON ASN.\r\nuntuk data 3 pegawai yang tidak terdaftar di Pengumuman PPPK Paru waktu diberikan Gaji dan THR sampai bulan Desember 2025.', 'berkoodinasi dengan Inspektorat terkait pembayaran Gaji dan THR untuk 3 Orang Pegawai yang tidak terdaftar di PPPK Paru Waktu.', NULL, '2025');
INSERT INTO b VALUES('22289292', '8.01.02', 'PROGRAM PENGUATAN IDEOLOGI PANCASILA DAN KARAKTER KEBANGSAAN', '8.01.0.00.0.00.25.0000', '2516803850', 1, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('22289292', '8.01.02', 'PROGRAM PENGUATAN IDEOLOGI PANCASILA DAN KARAKTER KEBANGSAAN', '8.01.0.00.0.00.25.0000', '2516803850', 3, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('22289292', '8.01.02', 'PROGRAM PENGUATAN IDEOLOGI PANCASILA DAN KARAKTER KEBANGSAAN', '8.01.0.00.0.00.25.0000', '2516803850', 4, 'Ketersedian Anggaran untuk menunjang Kegiatan Pembentukan Paskibraka dirasa kurang cukup, mengingat aksesbitas ke lokasi Rekrutmen Calon Anggota Paskibraka cukup jauh, \r\n\r\nkurang nya minat calon Paskibraka untuk bergabung dikarenakan Dana Darmawisata tidak tersedia.', 'rasa Nasionalisme yang dimiliki oleh Panitia dan Peserta Paskibraka, sehingga dapat melaksanakan Kegiatan dengan Ketersediaan anggaran yang ada.', 'berkoordinasi TAPD untuk mekakukan penyesuai Anggaran yang tersedia.', NULL, '2025');
INSERT INTO b VALUES('22289297', '8.01.03', 'PROGRAM PENINGKATAN PERAN PARTAI POLITIK DAN LEMBAGA PENDIDIKAN MELALUI PENDIDIKAN POLITIK DAN PENGEMBANGAN ETIKA SERTA BUDAYA POLITIK', '8.01.0.00.0.00.25.0000', '13280942910', 1, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('22289297', '8.01.03', 'PROGRAM PENINGKATAN PERAN PARTAI POLITIK DAN LEMBAGA PENDIDIKAN MELALUI PENDIDIKAN POLITIK DAN PENGEMBANGAN ETIKA SERTA BUDAYA POLITIK', '8.01.0.00.0.00.25.0000', '13280942910', 3, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('22289297', '8.01.03', 'PROGRAM PENINGKATAN PERAN PARTAI POLITIK DAN LEMBAGA PENDIDIKAN MELALUI PENDIDIKAN POLITIK DAN PENGEMBANGAN ETIKA SERTA BUDAYA POLITIK', '8.01.0.00.0.00.25.0000', '13280942910', 4, 'Anggaran Rasional sehingga terdapat kegiatan dapat dilaksanakan pada kegiatan Sosialisasi Pendidikan Politik Ke Masyarakat Mahakam Ulu,\r\npenyerapan Anggaran Bantuan KEUANGAN Partai Politik dilaksanan di Akhir Tahun karena terjadi perolehan suara dan Partai yang menerima bantuan Keuangan Partai Politik', 'melaksakan Kegiatan sesuai dengan keadaan Anggaran yang tersedia di kegiatan sosialisasi Pendidikan Politik di 5 Kecamatan.\r\n\r\nuntuk Pemberian Bantuan ke Partai dapat diberikan sesuai dengan ketentuan yang berlaku dan kesediaan Anggaran.', 'untuk Partai Politik yang menerima bantuan keuangan diharapkan melaporkan Realisasi Penggunaan Dana Bantuan Partai Anggaran', NULL, '2025');
INSERT INTO b VALUES('22289302', '8.01.04', 'PROGRAM PEMBERDAYAAN DAN PENGAWASAN ORGANISASI KEMASYARAKATAN', '8.01.0.00.0.00.25.0000', '219636300', 1, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('22289302', '8.01.04', 'PROGRAM PEMBERDAYAAN DAN PENGAWASAN ORGANISASI KEMASYARAKATAN', '8.01.0.00.0.00.25.0000', '219636300', 3, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('22289302', '8.01.04', 'PROGRAM PEMBERDAYAAN DAN PENGAWASAN ORGANISASI KEMASYARAKATAN', '8.01.0.00.0.00.25.0000', '219636300', 4, 'Rasional Anggaran dibidang Ormas dirasa merubah Target Perencanaan Pembinaan Organisasi Masyarakat  sehingga menurunnya Target nya.\r\n\r\nadanya Regulasi terkait Pembentukann Satuan Tugas  Organisasi berafiliasi Premanisme yang difasilitasi Oleh Daerah   sedangkan anggaran tidak tersedia.', 'Monitoring dan Evaluasi Ormas berjalan sesuai dengan Anggaran.', 'mengajukan Telaan staf penambahan Anggaran Untuk Tim SATGAS Melaksanakan Kegiatan Sosialisasi.', NULL, '2025');
INSERT INTO b VALUES('22289305', '8.01.05', 'PROGRAM PEMBINAAN DAN PENGEMBANGAN KETAHANAN EKONOMI, SOSIAL, DAN BUDAYA', '8.01.0.00.0.00.25.0000', '695965400', 1, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('22289305', '8.01.05', 'PROGRAM PEMBINAAN DAN PENGEMBANGAN KETAHANAN EKONOMI, SOSIAL, DAN BUDAYA', '8.01.0.00.0.00.25.0000', '695965400', 3, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('22289305', '8.01.05', 'PROGRAM PEMBINAAN DAN PENGEMBANGAN KETAHANAN EKONOMI, SOSIAL, DAN BUDAYA', '8.01.0.00.0.00.25.0000', '695965400', 4, 'Anggaran untuk kegiatan Sosialisasi Forum Kerukunan Umat ( FKUB )Beragama dan kegiatan Badan Narkotika serta pelaksanan Perayaan HUT Mahulu dirasa belum cukup.\r\n\r\npada FKUB untuk sekretariat yang digunakan terdapat kekurang Fasilitas seperti Meja Kursi dan perlengkapan Lainnya untuk menunjang kegiatan Tersebut.', 'melaksakan kegiatan sesuai dengan ketersediaan Anggaran yang ada untuk kegiatan FKUB dan Sosialsasi Badan Narkotika Kemasyarakat dan Siswa.\r\n\r\nmenggunakan Fasilitas seadanya untuk di sekretariat FKUB yang ada.', 'Berkoordinasi dengan Pihak sekolah dan Masyrakat Untuk melaksana Sosialisasi.\r\n\r\nBerkoornasi dengan Stack Holders FKUB.', NULL, '2025');
INSERT INTO b VALUES('22289308', '8.01.06', 'PROGRAM PENINGKATAN KEWASPADAAN NASIONAL DAN PENINGKATAN KUALITAS DAN FASILITASI PENANGANAN KONFLIK SOSIAL', '8.01.0.00.0.00.25.0000', '193017100', 1, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('22289308', '8.01.06', 'PROGRAM PENINGKATAN KEWASPADAAN NASIONAL DAN PENINGKATAN KUALITAS DAN FASILITASI PENANGANAN KONFLIK SOSIAL', '8.01.0.00.0.00.25.0000', '193017100', 3, NULL, NULL, NULL, NULL, '2025');
INSERT INTO b VALUES('22289308', '8.01.06', 'PROGRAM PENINGKATAN KEWASPADAAN NASIONAL DAN PENINGKATAN KUALITAS DAN FASILITASI PENANGANAN KONFLIK SOSIAL', '8.01.0.00.0.00.25.0000', '193017100', 4, 'Anggaran untuk Pelaksaan Kegiatan monitoring dan Sosialiasi ke kecamatan dirasa belum cukup untuk menujang kegiatan tersebut.\r\n\r\nketerbatasan Sumber Daya Manusia yang membidangi penanggani Konflik sehingga Menghambat menganalisis dugaan Konflik biasa dan luar biasa.', 'Melaksanakan dengan ketersedian sesuai Anggaran yang ada, dengan melakukan sosialisasi dan Monitoring ke Kecamatan di Kabupaten Mahakam Ulu.', 'berkoordinasi dengan Stack Holders terkait dan Forum di setiap Kecamatan dan Pemerintah Kabupaten Mahakam Ulu, terkait keadaan Harmonisasi masyarakat.', NULL, '2025');
INSERT INTO b VALUES('22289315', '1.05.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '1.05.0.00.0.00.26.0000', '14335096873', 1, '1. Keterbatasan kualitas dan kuantitas SDM\r\n2. Keterbatasan anggaran daerah\r\n3. Sarana dan prasarana pendukung yang belum memadai\r\n4. Koordinasi lintas bidang yang belum optimal\r\n5. Perubahan kebijakan dan regulasi yang dinamis', '1. Landasan regulasi yang kuat\r\n2. Dukungan pimpinan daerah dan perangkat daerah\r\n3. Kebutuhan peningkatan tata kelola BPBD\r\n4. Integrasi dengan sistem perencanaan dan penganggaran daerah\r\n5. Perkembangan teknologi informasi', '1. Peningkatan kapasitas SDM\r\n2. Optimalisasi perencanaan dan penganggaran program penunjang\r\n3. Penguatan koordinasi internal\r\n4. Pemanfaatan teknologi informas\r\n5. Peningkatan sarana dan prasarana pendukung\r\n6. Monitoring dan evaluasi berkelanjutan', NULL, '2025');
INSERT INTO b VALUES('22289315', '1.05.01', 'PROGRAM PENUNJANG URUSAN PEMERINTAHAN DAERAH KABUPATEN/KOTA', '1.05.0.00.0.00.26.0000', '14335096873', 3, '1. Keterbatasan kualitas dan kuantitas SDM\r\n2. Keterbatasan anggaran daerah\r\n3. Sarana dan prasarana pendukung yang belum memadai\r\n4. Koordinasi lintas bidang yang belum optimal\r\n5. Perubahan kebijakan dan regulasi yang dinamis', '1. Landasan regulasi yang kuat\r\n2. Dukungan pimpinan daerah dan perangkat daerah\r\n3. Kebutuhan peningkatan tata kelola BPBD\r\n4. Integrasi dengan sistem perencanaan dan penganggaran daerah\r\n5. Perkembangan teknologi informasi', '1. Peningkatan kapasitas SDM\r\n2. Optimalisasi perencanaan dan penganggaran program penunjang\r\n3. Penguatan koordinasi internal\r\n4. Pemanfaatan teknologi informas\r\n5. Peningkatan sarana dan prasarana pendukung\r\n6. Monitoring dan evaluasi berkelanjutan', NULL, '2025');
